<?php

namespace Database\Seeders;

use Illuminate\Database\Seeder;
use App\Models\HsMasterGlobal;

class TopHsMasterSeeder extends Seeder
{
    public function run(): void
    {
        $records = $this->getRecords();
        $inserted = 0;

        foreach ($records as $record) {
            $exists = HsMasterGlobal::where('hs_code', $record['hs_code'])->exists();
            if (!$exists) {
                HsMasterGlobal::create(array_merge($record, [
                    'confidence_score' => 90,
                    'last_source' => 'seed',
                    'is_active' => true,
                ]));
                $inserted++;
            }
        }

        $this->command->info("TopHsMasterSeeder: Inserted {$inserted} new records. Skipped " . (count($records) - $inserted) . " existing.");
    }

